import software.amazon.awssdk.auth.credentials.{EnvironmentVariableCredentialsProvider, AwsBasicCredentials}
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model.PutObjectRequest

object AWSService {
  def main(args: Array[String]): Unit = {
    // Load credentials from environment variables
    val accessKeyId = System.getenv("AWS_ACCESS_KEY_ID")
    val secretAccessKey = System.getenv("AWS_SECRET_ACCESS_KEY")

    require(accessKeyId != null && secretAccessKey != null, "AWS credentials must be provided via environment variables.")

    // Create AWS credentials provider
    val awsCredentialsProvider = EnvironmentVariableCredentialsProvider.create()

    // Create S3 client with the credentials provider
    val s3Client: S3Client = S3Client.builder()
      .region(Region.US_EAST_1)
      .credentialsProvider(awsCredentialsProvider)
      .build()

    // Example operation: Upload a file to S3
    val bucketName = "your-bucket-name"
    val keyName = "your-key-name"
    val filePath = "path/to/your/file"

    val putObjectRequest = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(keyName)
      .build()

    s3Client.putObject(putObjectRequest, java.nio.file.Paths.get(filePath))

    println(s"File uploaded to S3 bucket $bucketName as $keyName")
  }
